import{_ as r,o,c as t,a3 as s}from"./chunks/framework.CqLY61E_.js";const h=JSON.parse('{"title":"Lab 07 — Agrégations","description":"","frontmatter":{"title":"Lab 07 — Agrégations","aside":false},"headers":[],"relativePath":"labs/lab07-agregations.md","filePath":"labs/lab07-agregations.md"}'),a={name:"labs/lab07-agregations.md"};function n(i,e,l,u,c,d){return o(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="🧪-laboratoire-07-—-agregations" tabindex="-1">🧪 Laboratoire 07 — Agrégations <a class="header-anchor" href="#🧪-laboratoire-07-—-agregations" aria-label="Permalink to &quot;🧪 Laboratoire 07 — Agrégations&quot;">​</a></h1><h2 id="travail-a-realiser" tabindex="-1">Travail à réaliser <a class="header-anchor" href="#travail-a-realiser" aria-label="Permalink to &quot;Travail à réaliser&quot;">​</a></h2><h3 id="base-de-donnees-a-utiliser-chinook" tabindex="-1">Base de données à utiliser (Chinook) <a class="header-anchor" href="#base-de-donnees-a-utiliser-chinook" aria-label="Permalink to &quot;Base de données à utiliser (Chinook)&quot;">​</a></h3><div class="my-6 rounded-lg border border-yellow-300 bg-yellow-50 p-4 text-yellow-900"><strong>Attention</strong><br> Ce laboratoire utilise la base de données <strong>Chinook</strong>.<br> Si vous ne l&#39;avez pas encore importée, référez-vous aux instructions du module : <a href="../modules/04-jointures-agregations/02-jointures#base-de-donnees-de-test-a-importer-chinook">Importer Chinook</a></div><p>Créez un nouveau script SQL dans DBeaver (portée : base de données <code>chinook</code>).</p><hr><p><a id="partie-1"></a></p><h2 id="partie-1-—-agregations-group-by-et-having" tabindex="-1">Partie 1 — Agrégations, <code>group by</code> et <code>having</code> <a class="header-anchor" href="#partie-1-—-agregations-group-by-et-having" aria-label="Permalink to &quot;Partie 1 — Agrégations, `group by` et `having`&quot;">​</a></h2><h2 id="_1-—-fonctions-d-agregation" tabindex="-1">1 — Fonctions d&#39;agrégation <a class="header-anchor" href="#_1-—-fonctions-d-agregation" aria-label="Permalink to &quot;1 — Fonctions d&#39;agrégation&quot;">​</a></h2><p>Écrivez les requêtes suivantes à l&#39;aide des fonctions <code>count</code>, <code>sum</code>, <code>avg</code>, <code>min</code> et <code>max</code>.</p><ol><li>Afficher le <strong>prix unitaire moyen</strong> de toutes les pistes.</li><li>Afficher la <strong>durée maximale</strong> et la <strong>durée minimale</strong> des pistes.</li><li>Afficher le <strong>nombre total de factures</strong>.</li><li>Pour chaque ligne de <code>ligne_facture</code>, calculez d&#39;abord son montant avec <code>quantite * prix_unitaire</code>, puis affichez le <strong>montant total</strong> obtenu en additionnant toutes ces lignes.</li></ol><hr><h2 id="_2-—-group-by" tabindex="-1">2 — <code>Group by</code> <a class="header-anchor" href="#_2-—-group-by" aria-label="Permalink to &quot;2 — `Group by`&quot;">​</a></h2><h3 id="a-regroupements-simples" tabindex="-1">a) Regroupements simples <a class="header-anchor" href="#a-regroupements-simples" aria-label="Permalink to &quot;a) Regroupements simples&quot;">​</a></h3><ol><li>Afficher le <strong>nombre de clients par ville</strong>. Trier par nombre décroissant, puis par ville.</li><li>Afficher le <strong>nombre de pistes par type de média</strong> (<code>media_type_id</code>).</li><li>Afficher le <strong>prix unitaire moyen des pistes par album</strong> (<code>album_id</code>).</li></ol><h3 id="b-group-by-avec-jointures" tabindex="-1">b) <code>Group by</code> avec jointures <a class="header-anchor" href="#b-group-by-avec-jointures" aria-label="Permalink to &quot;b) `Group by` avec jointures&quot;">​</a></h3><ol><li>Afficher, pour chaque <strong>type de média</strong>, son <strong>nom</strong> et le <strong>nombre de pistes</strong> associées.</li><li>Afficher, pour chaque <strong>album</strong>, son <strong>titre</strong> et le <strong>nombre de pistes</strong> qu&#39;il contient.</li><li>Afficher, pour chaque <strong>client</strong>, son <strong>prénom</strong>, son <strong>nom de famille</strong> et le <strong>nombre de factures</strong> associées.</li><li>Afficher, pour chaque <strong>genre</strong>, son <strong>nom</strong> et la <strong>durée moyenne des pistes</strong> de ce genre.</li></ol><h3 id="c-bien-choisir-les-colonnes-du-group-by" tabindex="-1">c) Bien choisir les colonnes du <code>group by</code> <a class="header-anchor" href="#c-bien-choisir-les-colonnes-du-group-by" aria-label="Permalink to &quot;c) Bien choisir les colonnes du `group by`&quot;">​</a></h3><p>Pour chacune des requêtes suivantes, écrivez une requête correcte en choisissant les bonnes colonnes à placer dans le <code>group by</code>.</p><ol><li>Afficher le <strong>nom de l&#39;artiste</strong> et le <strong>nombre d&#39;albums</strong> qu&#39;il possède.</li><li>Afficher le <strong>pays de facturation</strong> et le <strong>montant total facturé</strong> pour ce pays.</li><li>Afficher le <strong>nom du client</strong> et la <strong>somme de ses factures</strong>.</li></ol><hr><h2 id="_3-—-having" tabindex="-1">3 — <code>Having</code> <a class="header-anchor" href="#_3-—-having" aria-label="Permalink to &quot;3 — `Having`&quot;">​</a></h2><p>Dans cette section, mettez l&#39;accent sur la différence entre <code>where</code> et <code>having</code>.</p><h3 id="a-filtrer-des-groupes" tabindex="-1">a) Filtrer des groupes <a class="header-anchor" href="#a-filtrer-des-groupes" aria-label="Permalink to &quot;a) Filtrer des groupes&quot;">​</a></h3><ol><li>Afficher les <strong>villes</strong> qui contiennent <strong>au moins 2 clients</strong>.</li><li>Afficher les <strong>albums</strong> qui contiennent <strong>au moins 15 pistes</strong>.</li><li>Afficher les <strong>types de média</strong> qui ont <strong>au moins 20 pistes</strong>.</li><li>Afficher les <strong>clients</strong> dont le <strong>nombre de factures</strong> est d&#39;au moins 5.</li></ol><h3 id="b-bien-placer-where-et-having" tabindex="-1">b) Bien placer <code>where</code> et <code>having</code> <a class="header-anchor" href="#b-bien-placer-where-et-having" aria-label="Permalink to &quot;b) Bien placer `where` et `having`&quot;">​</a></h3><p>Pour chacune des requêtes suivantes :</p><ul><li>écrivez la requête complète</li><li>déterminez quelle condition doit aller dans <code>where</code></li><li>déterminez quelle condition doit aller dans <code>having</code></li></ul><ol><li>Afficher les <strong>pays de facturation</strong> dont le <strong>montant total facturé en 2009</strong> dépasse 100.</li><li>Afficher les <strong>genres</strong> dont la <strong>durée moyenne des pistes</strong> dépasse 300000 millisecondes, en ne considérant que les pistes dont le prix unitaire est supérieur ou égal à 0.99.</li><li>Afficher les <strong>albums</strong> qui contiennent au moins 5 pistes dont la durée dépasse 240000 millisecondes.</li><li>Afficher les clients du <strong>Canada</strong> dont le total des achats dépasse 20.</li><li>Afficher les albums qui contiennent au moins 8 pistes vendues à 0.99 ou plus.</li></ol><hr><p><a id="partie-2"></a></p><h2 id="partie-2-—-sous-requetes-correlees-et-synthese" tabindex="-1">Partie 2 — Sous-requêtes corrélées et synthèse <a class="header-anchor" href="#partie-2-—-sous-requetes-correlees-et-synthese" aria-label="Permalink to &quot;Partie 2 — Sous-requêtes corrélées et synthèse&quot;">​</a></h2><h2 id="_4-—-sous-requetes-correlees" tabindex="-1">4 — Sous-requêtes corrélées <a class="header-anchor" href="#_4-—-sous-requetes-correlees" aria-label="Permalink to &quot;4 — Sous-requêtes corrélées&quot;">​</a></h2><h3 id="a-avec-exists-et-not-exists" tabindex="-1">a) Avec <code>exists</code> et <code>not exists</code> <a class="header-anchor" href="#a-avec-exists-et-not-exists" aria-label="Permalink to &quot;a) Avec `exists` et `not exists`&quot;">​</a></h3><p>Écrivez deux sous-requêtes corrélées en utilisant explicitement <code>exists</code> et <code>not exists</code>.</p><ol><li>Afficher les <strong>artistes</strong> qui ont <strong>au moins un album</strong>.</li><li>Afficher les <strong>employés</strong> qui ne représentent <strong>aucun client</strong>.</li></ol><h3 id="b-deux-autres-sous-requetes-correlees" tabindex="-1">b) Deux autres sous-requêtes corrélées <a class="header-anchor" href="#b-deux-autres-sous-requetes-correlees" aria-label="Permalink to &quot;b) Deux autres sous-requêtes corrélées&quot;">​</a></h3><p>Écrivez les requêtes suivantes avec des sous-requêtes corrélées.</p><ol><li>Afficher les <strong>pistes</strong> dont le <strong>prix unitaire</strong> est supérieur au <strong>prix moyen des pistes du même type de média</strong>.</li><li>Afficher les <strong>factures</strong> dont le <strong>total</strong> est supérieur au <strong>montant moyen des factures du même pays de facturation</strong>.</li></ol><h2 id="_5-—-exercices-supplementaires" tabindex="-1">5 — Exercices supplémentaires <a class="header-anchor" href="#_5-—-exercices-supplementaires" aria-label="Permalink to &quot;5 — Exercices supplémentaires&quot;">​</a></h2><h3 id="a-synthese-—-group-by-et-having" tabindex="-1">a) Synthèse — <code>group by</code> et <code>having</code> <a class="header-anchor" href="#a-synthese-—-group-by-et-having" aria-label="Permalink to &quot;a) Synthèse — `group by` et `having`&quot;">​</a></h3><p>Afficher les <strong>albums</strong> dont la <strong>durée totale</strong> dépasse 3 000 000 millisecondes, avec le titre de l&#39;album et la durée totale.</p><h3 id="b-synthese-—-sous-requete-correlee" tabindex="-1">b) Synthèse — Sous-requête corrélée <a class="header-anchor" href="#b-synthese-—-sous-requete-correlee" aria-label="Permalink to &quot;b) Synthèse — Sous-requête corrélée&quot;">​</a></h3><p>Afficher les <strong>pistes</strong> dont la <strong>durée</strong> est supérieure à la <strong>durée moyenne des pistes de leur album</strong>.</p><hr><h2 id="defi-optionnel-—-reecriture-avec-jointure-et-group-by" tabindex="-1">Défi optionnel — Réécriture avec jointure et <code>group by</code> <a class="header-anchor" href="#defi-optionnel-—-reecriture-avec-jointure-et-group-by" aria-label="Permalink to &quot;Défi optionnel — Réécriture avec jointure et `group by`&quot;">​</a></h2><blockquote><p>Ce défi va au-delà des attentes du cours. Il n&#39;est pas obligatoire.</p></blockquote><p>Réécrivez les deux requêtes de la section <strong>4 b)</strong> sans sous-requête corrélée.</p><p>Contraintes :</p><ul><li>utilisez une jointure avec une requête agrégée</li><li>la requête agrégée doit contenir un <code>group by</code></li><li>donnez un alias clair au résultat agrégé</li></ul><h3 id="conseils-de-construction" tabindex="-1">Conseils de construction <a class="header-anchor" href="#conseils-de-construction" aria-label="Permalink to &quot;Conseils de construction&quot;">​</a></h3><ol><li>Écrivez d&#39;abord la requête qui calcule la valeur agrégée par groupe.</li><li>Vérifiez que cette requête retourne une ligne par groupe.</li><li>Joignez ensuite ce résultat à la table principale.</li><li>Terminez avec le filtre final dans le <code>where</code>.</li></ol><hr>',53)])])}const p=r(a,[["render",n]]);export{h as __pageData,p as default};
